import { Component } from '@angular/core';
import { Router } from '@angular/router';
import { FirebaseService } from './shared/firebase.service';


@Component({
  selector: 'app-root',
  templateUrl: './app.component.html',
  styleUrls: ['./app.component.css']
})
export class AppComponent {



  constructor(private service: FirebaseService, public router: Router) {}
  private flag: boolean;


  google() {
    this.service.logINGoogle().then((data) => {
      this.router.navigate(['/']);
      this.flag = true;
      console.log('conectado');
    }).catch(erro => {
      alert('Erro ....');
    });
  }
  facebook() {
    this.service.logINFace().then(data => {
      console.log(data);
    }).catch(e => {
      alert('Facebook não conectado ...');
    });
  }

  logOUT() {
    this.service.logOUTGoogle().then(data => {
      this.flag = false;
      console.log('deslocado');
    }).catch(e => {
      alert('Erro de fechamento ....');
    });
  }







}
